13510 bool BoUpSLP::matchesInversedZExtSelect(
13511     const TreeEntry &SelectTE,
13512     SmallVectorImpl<unsigned> &InversedCmpsIndices) const {
13513   assert(SelectTE.hasState() && SelectTE.getOpcode() == Instruction::Select &&
13514          "Expected select node.");
13515   SmallVector<std::pair<Instruction *, unsigned>> ZExts;
13516   for (auto [Idx, V] : enumerate(SelectTE.Scalars)) {
13517     auto *Inst = dyn_cast<Instruction>(V);
13518     if (!Inst || Inst->getOpcode() != Instruction::ZExt)
13519       continue;
13520     ZExts.emplace_back(Inst, Idx);
13521   }
13522   if (ZExts.empty())
13523     return false;
13524   const auto *CmpTE = getOperandEntry(&SelectTE, 0);
13525   const auto *Op1TE = getOperandEntry(&SelectTE, 1);
13526   const auto *Op2TE = getOperandEntry(&SelectTE, 2);
13527   // Compares must be alternate vectorized, and other operands must be gathers
13528   // or copyables.
13529   if (CmpTE->State != TreeEntry::Vectorize || !CmpTE->isAltShuffle() ||
13530       (CmpTE->getOpcode() != Instruction::ICmp &&
13531        CmpTE->getOpcode() != Instruction::FCmp) ||
13532       !Op1TE->ReorderIndices.empty() || !Op1TE->ReuseShuffleIndices.empty() ||
13533       !Op2TE->ReorderIndices.empty() || !Op2TE->ReuseShuffleIndices.empty())
13534     return false;
13535   // The operands must be buildvectors/copyables.
13536   if (!Op1TE->isGather() || !Op2TE->isGather())
13537     return false;
13538   // TODO: investigate opportunity for the vector nodes with copyables.
13539   auto *Cmp = CmpTE->getMainOp();
13540   CmpPredicate Pred;
13541   auto MatchCmp = m_Cmp(Pred, m_Value(), m_Value());
13542   if (!match(Cmp, MatchCmp))
13543     return false;
13544   CmpPredicate MainPred = Pred;
13545   CmpPredicate InversedPred(CmpInst::getInversePredicate(Pred),
13546                             Pred.hasSameSign());
13547   for (const auto [Idx, V] : enumerate(CmpTE->Scalars)) {
13548     if (!match(V, MatchCmp))
13549       continue;
13550     if (CmpPredicate::getMatching(MainPred, Pred))
13551       continue;
13552     if (!CmpPredicate::getMatching(InversedPred, Pred))
13553       return false;
13554     InversedCmpsIndices.push_back(Idx);
13555   }
13556 
13557   return !InversedCmpsIndices.empty();
13558 }
