13562   BaseGraphSize = VectorizableTree.size();
13563   // Turn graph transforming mode on and off, when done.
13564   class GraphTransformModeRAAI {
13565     bool &SavedIsGraphTransformMode;
13566 
13567   public:
13568     GraphTransformModeRAAI(bool &IsGraphTransformMode)
13569         : SavedIsGraphTransformMode(IsGraphTransformMode) {
13570       IsGraphTransformMode = true;
13571     }
