13574   // Operands are profitable if they are:
13575   // 1. At least one constant
13576   // or
13577   // 2. Splats
13578   // or
13579   // 3. Results in good vectorization opportunity, i.e. may generate vector
13580   // nodes and reduce cost of the graph.
13581   auto CheckOperandsProfitability = [this](Instruction *I1, Instruction *I2,
13582                                            const InstructionsState &S) {
