13588         Candidates, [this](ArrayRef<std::pair<Value *, Value *>> Cand) {
13589           return all_of(Cand,
13590                         [](const std::pair<Value *, Value *> &P) {
13591                           return isa<Constant>(P.first) ||
13592                                  isa<Constant>(P.second) || P.first == P.second;
13593                         }) ||
13594                  findBestRootPair(Cand, LookAheadHeuristics::ScoreSplatLoads);
13595         });
13596   };
13597 
13598   // Try to reorder gather nodes for better vectorization opportunities.
13599   for (unsigned Idx : seq<unsigned>(BaseGraphSize)) {
13600     TreeEntry &E = *VectorizableTree[Idx];
13601     if (E.isGather())
13602       reorderGatherNode(E);
13603   }
13604 
