13616   auto AreReusedScalars = [&](const TreeEntry *TE, ArrayRef<Value *> VL,
13617                               function_ref<bool(Value *)> CheckContainer) {
13618     return TE->isSame(VL) || all_of(VL, [&](Value *V) {
13619              if (isa<PoisonValue>(V))
13620                return true;
13621              auto *I = dyn_cast<Instruction>(V);
13622              if (!I)
13623                return false;
13624              return is_contained(TE->Scalars, I) || CheckContainer(I);
13625            });
13626   };
13627   auto CheckForSameVectorNodes = [&](const TreeEntry &E) {
13628     if (E.hasState()) {
13629       if (ArrayRef<TreeEntry *> TEs = getTreeEntries(E.getMainOp());
13630           !TEs.empty() && any_of(TEs, [&](const TreeEntry *TE) {
13631             return AreReusedScalars(TE, E.Scalars, [&](Value *V) {
13632               ArrayRef<TreeEntry *> VTEs = getTreeEntries(V);
13633               return !VTEs.empty() && any_of(VTEs, [&](const TreeEntry *TE) {
13634                 return is_contained(TEs, TE);
13635               });
13636             });
13637           }))
13638         return true;
13639       ;
13640       if (ArrayRef<TreeEntry *> TEs = getSplitTreeEntries(E.getMainOp());
13641           !TEs.empty() && any_of(TEs, [&](const TreeEntry *TE) {
